        int len2 = arr[idx++];
        int[] seq2 = new int[len2];
        for (int i = 0; i < len2; i++) seq2[i] = arr[idx++];

        int[,] dp = new int[len1 + 1, len2 + 1];

        for (int i = 0; i <= len1; i++) dp[i, 0] = i;
        for (int j = 0; j <= len2; j++) dp[0, j] = j;

        for (int i = 1; i <= len1; i++)
